<script>
function erroBE(msg){document.getElementById('erro-be-texto').textContent=msg;document.getElementById('erro-be').style.display='flex';document.getElementById('resultado-be').classList.remove('show');}
function limparErroBE(){document.getElementById('erro-be').style.display='none';}
function calcularBreakEven(){const fixo=parseFloat(document.getElementById('be-fixo').value);const preco=parseFloat(document.getElementById('be-preco').value);const variavel=parseFloat(document.getElementById('be-variavel').value);limparErroBE();if(isNaN(fixo)||isNaN(preco)||isNaN(variavel)||fixo<0||preco<=0||variavel<0){erroBE('Preencha custos e preço com valores válidos.');return;}const margem=preco-variavel;if(margem<=0){erroBE('O preço por unidade precisa ser maior que o custo variável.');return;}const unidades=fixo/margem;const faturamento=unidades*preco;document.getElementById('be-unidades').textContent=fmtNum(unidades,2)+' un.';document.getElementById('be-faturamento').textContent='R$ '+fmtBRL(faturamento);document.getElementById('be-detalhe').textContent='Margem de contribuição unitária: R$ '+fmtBRL(margem)+'.';showResult('resultado-be');}
function limparBreakEven(){document.getElementById('be-fixo').value='';document.getElementById('be-preco').value='';document.getElementById('be-variavel').value='';document.getElementById('resultado-be').classList.remove('show');limparErroBE();}
function copiarBreakEven(button){if(!document.getElementById('resultado-be').classList.contains('show')){erroBE('Calcule o ponto de equilíbrio antes de copiar o resultado.');return;}copyToClipboard('Break even: '+document.getElementById('be-unidades').textContent+'\nFaturamento necessário: '+document.getElementById('be-faturamento').textContent,button);}
</script>
